from collections import deque

def multi_hop_bfs(kg, start_entity: str, k: int) -> dict:
    visited = {start_entity: 0}
    queue = deque([(start_entity, 0)])
    while queue:
        entity, hop = queue.popleft()
        if hop >= k:
            continue
        for _, neighbor in kg.neighbors(entity):
            if neighbor not in visited:
                visited[neighbor] = hop + 1
                queue.append((neighbor, hop + 1))
    return visited

def entities_at_hop(kg, start_entity: str, k: int) -> set:
    distances = multi_hop_bfs(kg, start_entity, k)
    return {e for e, d in distances.items() if d == k}

